mapper.select:
select a.cmpycd, a.reqymd as ordymd, a.reqno as orowno, a.gubun, a.custcd, b.custnm,
       a.itemcd, c.itemnm, c.itsize, c.unit, a.planqty as ordqty, a.napgiymd, a.bigo, a.updemp
  from hppl150t_tbl a
  left join haba020t_tbl b on a.cmpycd = b.cmpycd and a.custcd = b.custcd
  left join hsba010t_tbl c on a.cmpycd = c.cmpycd and a.itemcd = c.itemcd
 where a.cmpycd = #{cmpycd}
   and a.reqymd between #{frymd} and #{toymd}
   and a.gubun = #{gubun}
 order by a.reqymd desc, a.reqno desc

mapper.insert:

    select dbo.lpad(isnull(max(dbo.lpad(reqno,3,'0'))+1,1),3,'0')
      from hppl150t_tbl
     where cmpycd = #{cmpycd} and reqymd = #{ordymd}

insert into hppl150t_tbl (
    cmpycd, reqymd, reqno, gubun, custcd, itemcd, planqty, napgiymd, bigo, addtime, updtime, updemp
) values (
    #{cmpycd}, #{ordymd}, #{orowno}, #{gubun}, #{custcd}, #{itemcd}, #{ordqty}, #{napgiymd}, #{bigo}, getdate(), getdate(), #{updemp}
)

mapper.update:
update hppl150t_tbl
   set custcd = #{custcd},
       itemcd = #{itemcd},
       planqty = #{ordqty},
       napgiymd = #{napgiymd},
       bigo = #{bigo},
       updtime = getdate(),
       updemp = #{updemp}
 where cmpycd = #{cmpycd}
   and reqymd = #{ordymd}
   and reqno = #{orowno}

mapper.delete:
delete from hppl150t_tbl
 where cmpycd = #{cmpycd}
   and reqymd = #{ordymd}
   and reqno = #{orowno}

mapper.select:
select a.yymmdd, a.ser, case datepart(dw, convert(date, a.yymmdd)) when 1 then '일' when 2 then '월' when 3 then '화' when 4 then '수' when 5 then '목' when 6 then '금' when 7 then '토' end as day_nm, a.itemcd, b.itemnm, b.itsize, a.custcd, c.custnm as custnm, a.linecd, d.linenm, a.progcd, e.prognm, a.planqty, a.ordqty, a.napgiymd, a.ordymd, a.ordno, a.orowno, isnull(f.gadrate, 0) as gadrate, /* 가동율 */ isnull(f.jungrate, 0) as jungrate, /* 양품율 */ /* 🚀 capahh와 stdworkhh 중 있는 값을 우선 사용 */ case when isnull(f.capahh, 0) > 0 then f.capahh else isnull(f.stdworkhh, 0) end * 60 as capahh, isnull(f.gadtmdd, 0) as gadtmdd, /* 가동시간 */ isnull(f.pqtytt, 0) as pqtytt, /* 일생산량 */ isnull(f.pqtydd, 0) as unit_capa /* 일생산능력 */ from hppl160t_tbl a left join hsba010t_tbl b on a.cmpycd = b.cmpycd and a.itemcd = b.itemcd left join haba020t_tbl c on a.cmpycd = c.cmpycd and a.custcd = c.custcd left join hpba130t_tbl d on a.cmpycd = d.cmpycd and a.linecd = d.linecd left join hpba100t_tbl e on a.cmpycd = e.cmpycd and a.linecd = e.linecd and a.progcd = e.progcd left join hpba200t_tbl f on a.cmpycd = f.cmpycd and a.itemcd = f.itemcd and a.linecd = f.linecd and a.progcd = f.progcd where a.cmpycd = #{cmpycd} and a.yymmdd between #{frymd} and #{toymd}
and a.linecd = #{linecd}
order by a.yymmdd, a.linecd, a.progcd, a.ser

select a.cmpycd, a.yymmdd, a.ser, a.ordymd, a.ordno, a.orowno,
       a.custcd, a.itemcd, a.linecd, a.progcd, a.ordqty, a.planqty, a.napgiymd, a.updemp
  from hppl160t_tbl a
 where a.cmpycd = #{cmpycd}
   and a.yymmdd = #{oldyymmdd}
   and a.ser    = #{oldser}

select count(*) from HPPL160T_TBL
 where cmpycd = #{cmpycd}
   and ordymd = #{ordymd} 
   and ordno  = #{ordno} 
   and orowno = #{orowno}

select holi_dt, gubun 
  from pd_holiday
 where cmpycd = #{cmpycd} 
   and holi_dt = #{yymmdd}

select a.linecd, a.progcd, a.itemcd, a.mitemcd, a.inqty, a.losrate
  from hpba210t_tbl a
 where a.cmpycd = #{cmpycd}
   and a.itemcd = #{itemcd}
   and a.linecd = #{linecd}
 order by a.progcd asc

select dbo.lpad(isnull(max(dbo.lpad(ser,3,'0'))+1,1),3,'0')
from hppl160t_tbl
where cmpycd = #{cmpycd} and yymmdd = #{yymmdd}

mapper.insert:

    select dbo.lpad(isnull(max(dbo.lpad(ser,3,'0')),0)+1,3,'0')
      from hppl160t_tbl
     where cmpycd = #{cmpycd} and yymmdd = #{yymmdd}

insert into hppl160t_tbl (
    cmpycd, yymmdd, ser, ordymd, ordno, orowno, custcd, itemcd, linecd, progcd,
    ordqty, planqty, napgiymd, addtime, updtime, updemp
)
select #{cmpycd}, #{yymmdd},
       dbo.lpad(cast(#{ser} as int) + row_number() over (order by b.progord, b.progcd) - 1, 3, '0'),
       #{ordymd}, #{ordno}, #{orowno}, #{custcd}, #{itemcd}, #{linecd}, b.progcd,
       0, #{planqty}, #{napgiymd}, getdate(), getdate(), #{updemp}
  from HPBA200T_TBL b
 where b.cmpycd = #{cmpycd}
   and b.itemcd = #{itemcd}
   and b.linecd = #{linecd}

insert into hppl160t_tbl (
    cmpycd, yymmdd, ser, ordymd, ordno, orowno, custcd, itemcd, linecd, progcd,
    ordqty, planqty, napgiymd, addtime, updtime, updemp
) values (
    #{cmpycd}, #{yymmdd}, #{ser}, #{ordymd}, #{ordno}, #{orowno}, #{custcd}, #{itemcd}, #{linecd}, #{progcd},
    #{ordqty}, #{planqty}, #{napgiymd}, getdate(), getdate(), #{updemp}
)

mapper.update:
update hppl160t_tbl
   set itemcd = #{itemcd},
       custcd = #{custcd},
       linecd = #{linecd},
       progcd = #{progcd},
       planqty = #{planqty},
       napgiymd = #{napgiymd},
       updtime = getdate(),
       updemp = #{updemp}
 where cmpycd = #{cmpycd}
   and yymmdd = #{yymmdd}
   and ser = #{ser}
